package picod

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type Config struct {
	Port      string
	Workspace string
}

type ExecuteRequest struct {
	Command     []string          `json:"command" binding:"required,min=1"`
	Timeout     string            `json:"timeout"`
	WorkingDir  string            `json:"working_dir"`
	Env         map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout     string `json:"stdout"`
	Stderr     string `json:"stderr"`
	ExitCode   int    `json:"exit_code"`
	Duration   float64 `json:"duration"`
	StartTime  string `json:"start_time"`
	EndTime    string `json:"end_time"`
}

type UploadFileRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode"`
}

type FileInfo struct {
	Path     string `json:"path"`
	Size     int64  `json:"size"`
	Modified string `json:"modified"`
	Mode     string `json:"mode"`
}

type FileEntry struct {
	Name     string `json:"name"`
	Size     int64  `json:"size"`
	Modified string `json:"modified"`
	Mode     string `json:"mode"`
	IsDir    bool   `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type HealthResponse struct {
	Status  string `json:"status"`
	Service string `json:"service"`
	Version string `json:"version"`
	Uptime  string `json:"uptime"`
}

func sanitizePath(workspace, inputPath string) (string, error) {
	cleanPath := filepath.Clean(inputPath)
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("path escapes workspace jail")
	}

	absPath := filepath.Join(workspace, cleanPath)
	resolvedPath, err := filepath.Abs(absPath)
	if err != nil {
		return "", fmt.Errorf("failed to resolve absolute path: %w", err)
	}

	workspaceAbs, err := filepath.Abs(workspace)
	if err != nil {
		return "", fmt.Errorf("failed to resolve workspace path: %w", err)
	}

	if !strings.HasPrefix(resolvedPath, workspaceAbs) {
		return "", fmt.Errorf("path escapes workspace jail")
	}

	return resolvedPath, nil
}

func parseFileMode(modeStr string) (os.FileMode, error) {
	if modeStr == "" {
		return 0644, nil
	}

	var mode uint64
	_, err := fmt.Sscanf(modeStr, "%o", &mode)
	if err != nil {
		return 0, fmt.Errorf("invalid file mode: %w", err)
	}

	fileMode := os.FileMode(mode)
	if fileMode > 0777 {
		return 0644, nil
	}

	return fileMode, nil
}

func getRelativePath(workspace, fullPath string) string {
	workspaceAbs, _ := filepath.Abs(workspace)
	fullPathAbs, _ := filepath.Abs(fullPath)
	relPath, _ := filepath.Rel(workspaceAbs, fullPathAbs)
	return relPath
}

package picod

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	TimeoutExitCode = 124
	MaxBodySize     = 10 << 20
	DefaultTimeout  = 60 * time.Second
)

type AuthManager struct {
	publicKey *rsa.PublicKey
}

func NewAuthManager(publicKeyPEM []byte) (*AuthManager, error) {
	block, _ := pem.Decode(publicKeyPEM)
	if block == nil {
		return nil, fmt.Errorf("failed to decode PEM block containing public key")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return nil, fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return nil, fmt.Errorf("not an RSA public key")
	}

	return &AuthManager{publicKey: rsaPub}, nil
}

func (a *AuthManager) AuthMiddleware(c *gin.Context) {
	authHeader := c.GetHeader("Authorization")
	if authHeader == "" {
		c.JSON(http.StatusUnauthorized, gin.H{
			"error":  "Missing authorization header",
			"code":   401,
			"detail": "Authorization header is required",
		})
		c.Abort()
		return
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || parts[0] != "Bearer" {
		c.JSON(http.StatusUnauthorized, gin.H{
			"error":  "Invalid authorization header",
			"code":   401,
			"detail": "Header must be in format: Bearer <token>",
		})
		c.Abort()
		return
	}

	token, err := jwt.Parse(parts[1], func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return a.publicKey, nil
	}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(1*time.Minute))

	if err != nil {
		c.JSON(http.StatusUnauthorized, gin.H{
			"error":  "Invalid token",
			"code":   401,
			"detail": err.Error(),
		})
		c.Abort()
		return
	}

	if !token.Valid {
		c.JSON(http.StatusUnauthorized, gin.H{
			"error":  "Invalid token",
			"code":   401,
			"detail": "Token is not valid",
		})
		c.Abort()
		return
	}

	c.Next()
}

package picod

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

type Server struct {
	config      *Config
	authManager *AuthManager
	startTime   time.Time
}

func NewServer(config *Config, authManager *AuthManager) (*Server, error) {
	if config.Workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
		config.Workspace = wd
	}

	if err := os.MkdirAll(config.Workspace, 0755); err != nil {
		return nil, fmt.Errorf("failed to create workspace directory: %w", err)
	}

	return &Server{
		config:      config,
		authManager: authManager,
		startTime:   time.Now(),
	}, nil
}

func (s *Server) Start() error {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	router.GET("/health", s.handleHealth)

	apiGroup := router.Group("/api")
	apiGroup.Use(s.authManager.AuthMiddleware)
	apiGroup.Use(func(c *gin.Context) {
		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	})
	{
		apiGroup.POST("/execute", s.handleExecute)
		apiGroup.POST("/files", s.handleFileUpload)
		apiGroup.GET("/files", s.handleListFiles)
		apiGroup.GET("/files/*path", s.handleDownloadFile)
	}

	addr := ":" + s.config.Port
	server := &http.Server{
		Addr:              addr,
		Handler:           router,
		ReadHeaderTimeout: 10 * time.Second,
	}

	return server.ListenAndServe()
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, HealthResponse{
		Status:  "ok",
		Service: "PicoD",
		Version: "0.0.1",
		Uptime:  time.Since(s.startTime).String(),
	})
}

func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "command cannot be empty",
			"code":  400,
		})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		parsedTimeout, err := time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid timeout format: %v", err),
				"code":  400,
			})
			return
		}
		timeout = parsedTimeout
	}

	workingDir := s.config.Workspace
	if req.WorkingDir != "" {
		sanitized, err := sanitizePath(s.config.Workspace, req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid working directory: %v", err),
				"code":  400,
			})
			return
		}
		workingDir = sanitized
	}

	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)
	cmd.Dir = workingDir

	env := os.Environ()
	for k, v := range req.Env {
		env = append(env, fmt.Sprintf("%s=%s", k, v))
	}
	cmd.Env = env

	stdout := &bytes.Buffer{}
	stderr := &bytes.Buffer{}
	cmd.Stdout = stdout
	cmd.Stderr = stderr

	startTime := time.Now()
	err := cmd.Run()
	endTime := time.Now()

	exitCode := 0
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			stderr.WriteString(fmt.Sprintf("Command timed out after %d seconds\n", int(timeout.Seconds())))
		} else if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}
	}

	duration := endTime.Sub(startTime).Seconds()

	c.JSON(http.StatusOK, ExecuteResponse{
		Stdout:   stdout.String(),
		Stderr:   stderr.String(),
		ExitCode: exitCode,
		Duration: duration,
		StartTime: startTime.Format(time.RFC3339),
		EndTime:   endTime.Format(time.RFC3339),
	})
}

func (s *Server) handleFileUpload(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")
	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
	} else {
		s.handleJSONUpload(c)
	}
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	fileHeader, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("failed to get file: %v", err),
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(s.config.Workspace, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directories: %v", err),
			"code":  500,
		})
		return
	}

	src, err := fileHeader.Open()
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("failed to open uploaded file: %v", err),
			"code":  400,
		})
		return
	}
	defer src.Close()

	dst, err := os.Create(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create file: %v", err),
			"code":  500,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	modeStr := c.PostForm("mode")
	mode, err := parseFileMode(modeStr)
	if err == nil {
		os.Chmod(sanitizedPath, mode)
	}

	info, _ := os.Stat(sanitizedPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     getRelativePath(s.config.Workspace, sanitizedPath),
		Size:     info.Size(),
		Modified: info.ModTime().Format(time.RFC3339),
		Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
	})
}

func (s *Server) handleJSONUpload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	content, err := decodeBase64(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid base64 content: %v", err),
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(s.config.Workspace, req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to create directories: %v", err),
			"code":  500,
		})
		return
	}

	if err := os.WriteFile(sanitizedPath, content, 0644); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to write file: %v", err),
			"code":  500,
		})
		return
	}

	mode, err := parseFileMode(req.Mode)
	if err == nil {
		os.Chmod(sanitizedPath, mode)
	}

	info, _ := os.Stat(sanitizedPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     getRelativePath(s.config.Workspace, sanitizedPath),
		Size:     info.Size(),
		Modified: info.ModTime().Format(time.RFC3339),
		Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
	})
}

func (s *Server) handleListFiles(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' query parameter",
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(s.config.Workspace, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "Directory not found",
				"code":  404,
			})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": err.Error(),
				"code":  500,
			})
		}
		return
	}

	var files []FileEntry
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime().Format(time.RFC3339),
			Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) handleDownloadFile(c *gin.Context) {
	path := c.Param("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  400,
		})
		return
	}

	sanitizedPath, err := sanitizePath(s.config.Workspace, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  400,
		})
		return
	}

	info, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "File not found",
				"code":  404,
			})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": err.Error(),
				"code":  500,
			})
		}
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is a directory, not a file",
			"code":  400,
		})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(path)))

	ext := filepath.Ext(path)
	mimeType := "application/octet-stream"
	if ext != "" {
		if mt := getMimeType(ext); mt != "" {
			mimeType = mt
		}
	}
	c.Header("Content-Type", mimeType)

	c.File(sanitizedPath)
}

func decodeBase64(s string) ([]byte, error) {
	return nil, nil
}

func getMimeType(ext string) string {
	return ""
}

package main

import (
	"flag"
	"fmt"
	"log"
	"os"

	"github.com/volcano-sh/agentcube/pkg/picod"
)

func main() {
	port := flag.String("port", "8080", "Port to listen on")
	workspace := flag.String("workspace", "", "Workspace directory")
	flag.Parse()

	publicKeyPEM, err := os.ReadFile(os.Getenv("PICOD_AUTH_PUBLIC_KEY"))
	if err != nil {
		log.Fatalf("Failed to read public key: %v", err)
	}

	authManager, err := picod.NewAuthManager(publicKeyPEM)
	if err != nil {
		log.Fatalf("Failed to create auth manager: %v", err)
	}

	config := &picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server, err := picod.NewServer(config, authManager)
	if err != nil {
		log.Fatalf("Failed to create server: %v", err)
	}

	if err := server.Start(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

