	}

	return &Server{
		config:      config,
		authManager: authManager,
		startTime:   time.Now(),
	}, nil
}

func (s *Server) Start() error {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	router.GET("/health", s.handleHealth)

	apiGroup := router.Group("/api")
	apiGroup.Use(s.authManager.AuthMiddleware)
	apiGroup.Use(func(c *gin.Context) {
		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, types.MaxBodySize)
		c.Next()
	})
	{
		apiGroup.POST("/execute", s.handleExecute)
		apiGroup.POST("/files", s.handleFileUpload)
		apiGroup.GET("/files", s.handleListFiles)
		apiGroup.GET("/files/*path", s.handleDownloadFile)
	}

	addr := ":" + s.config.Port
	server := &http.Server{
