package picod

import (
	"context"
	"os/exec"
	"testing"
	"time"

	"github.com/volcano-sh/agentcube/pkg/picod/pkg/types"
)

func TestExecuteCommand(t *testing.T) {
	tests := []struct {
		name      string
		command   []string
		wantExit  int
		wantStdout string
	}{
		{
			name:      "simple echo",
			command:   []string{"echo", "hello"},
			wantExit:  0,
			wantStdout: "hello\n",
		},
		{
			name:      "python print",
			command:   []string{"python3", "-c", "print('hello')"},
			wantExit:  0,
			wantStdout: "hello\n",
		},
		{
			name:    "command timeout",
			command: []string{"sleep", "10"},
			wantExit: types.TimeoutExitCode,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()

			cmd := exec.CommandContext(ctx, tt.command[0], tt.command[1:]...)

			stdout, err := cmd.CombinedOutput()
			exitCode := 0
			if err != nil {
				if exitErr, ok := err.(*exec.ExitError); ok {
					exitCode = exitErr.ExitCode()
				}
			}

			if exitCode != tt.wantExit {
				t.Errorf("exit code = %d, want %d", exitCode, tt.wantExit)
			}

			if tt.wantStdout != "" && string(stdout) != tt.wantStdout {
				t.Errorf("stdout = %q, want %q", string(stdout), tt.wantStdout)
			}
		})
	}
}

func TestSanitizePath(t *testing.T) {
	tests := []struct {
		name      string
		workspace string
		input     string
		wantErr   bool
	}{
		{
			name:      "valid path",
			workspace: "/tmp/workspace",
			input:     "subdir/file.txt",
			wantErr:   false,
		},
		{
			name:      "path escape attempt",
			workspace: "/tmp/workspace",
			input:     "../../../etc/passwd",
			wantErr:   true,
		},
		{
			name:      "absolute path in workspace",
			workspace: "/tmp/workspace",
			input:     "/tmp/workspace/subdir",
			wantErr:   false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := types.SanitizePath(tt.workspace, tt.input)
			if (err != nil) != tt.wantErr {
				t.Errorf("SanitizePath() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestParseFileMode(t *testing.T) {
	tests := []struct {
		input    string
		wantMode os.FileMode
	}{
		{"", 0644},
		{"0644", 0644},
		{"0755", 0755},
		{"0600", 0600},
		{"invalid", 0644},
		{"7777", 0644},
	}

	for _, tt := range tests {
		t.Run(tt.input, func(t *testing.T) {
			mode, _ := types.ParseFileMode(tt.input)
			if mode != tt.wantMode {
				t.Errorf("ParseFileMode() = %v, want %v", mode, tt.wantMode)
			}
		})
	}
}

package auth

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

func generateTestKeyPair() (*rsa.PrivateKey, string, error) {
	privateKey, err := rsa.GenerateKey(nil, 2048)
	if err != nil {
		return nil, "", err
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return nil, "", err
	}

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	return privateKey, string(publicKeyPEM), nil
}

func generateTestToken(privateKey *rsa.PrivateKey) string {
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"sub": "test-user",
		"exp": jwt.NewNumericDate(jwt.TimeFunc().Add(time.Hour)),
		"iat": jwt.NewNumericDate(jwt.TimeFunc()),
	})

	tokenString, _ := token.SignedString(privateKey)
	return tokenString
}

func TestAuthMiddleware(t *testing.T) {
	gin.SetMode(gin.TestMode)

	privateKey, publicKeyPEM, err := generateTestKeyPair()
	if err != nil {
		t.Fatalf("Failed to generate key pair: %v", err)
	}

	authManager, err := NewAuthManager([]byte(publicKeyPEM))
	if err != nil {
		t.Fatalf("Failed to create auth manager: %v", err)
	}

	tests := []struct {
		name       string
		token      string
		wantStatus int
	}{
		{
			name:       "missing header",
			token:      "",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:       "invalid header format",
			token:      "invalid",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:       "valid token",
			token:      generateTestToken(privateKey),
			wantStatus: http.StatusOK,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			router := gin.New()
			router.Use(authManager.AuthMiddleware)
			router.GET("/test", func(c *gin.Context) {
				c.Status(http.StatusOK)
			})

			req, _ := http.NewRequest("GET", "/test", nil)
			if tt.token != "" {
				req.Header.Set("Authorization", "Bearer "+tt.token)
			}

			w := httptest.NewRecorder()
			router.ServeHTTP(w, req)

			if w.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", w.Code, tt.wantStatus)
			}
		})
	}
}

