package store

import (
	"context"
	"encoding/json"
	"fmt"
	"strconv"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
)

type RedisStore struct {
	client *redis.Client
	once   sync.Once
}

func NewRedisStore(addr, password string) (*RedisStore, error) {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to Redis: %w", err)
	}

	return &RedisStore{client: client}, nil
}

func (r *RedisStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox ExpiresAt cannot be zero")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	key := sessionKey(sandbox.SessionID)
	pipe := r.client.Pipeline()

	pipe.Set(ctx, key, data, 0)
	pipe.ZAdd(ctx, expiryKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, activityKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := r.client.Get(ctx, key).Result()
	if err != nil {
		if err == redis.Nil {
			return nil, &ErrNotFound{}
		}
		return nil, fmt.Errorf("failed to get session: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

func (r *RedisStore) UpdateSandbox(ctx context.Context, sessionID string, sandbox *SandboxInfo) error {
	key := sessionKey(sessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	result, err := r.client.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return fmt.Errorf("failed to update session: %w", err)
	}
	if !result {
		return fmt.Errorf("key not exists")
	}

	return nil
}

func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)
	pipe := r.client.Pipeline()

	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryKey, sessionID)
	pipe.ZRem(ctx, activityKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*SandboxInfo, error) {
	sessionIDs, err := r.client.ZRangeByScore(ctx, expiryKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to list expired sessions: %w", err)
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*SandboxInfo, error) {
	sessionIDs, err := r.client.ZRangeByScore(ctx, activityKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to list inactive sessions: %w", err)
	}

	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session ID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return fmt.Errorf("failed to check session existence: %w", err)
	}
	if exists == 0 {
		return &ErrNotFound{}
	}

	return r.client.ZAdd(ctx, activityKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (r *RedisStore) Close() error {
	return r.client.Close()
}

func (r *RedisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	values, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to load sessions: %w", err)
	}

	var sandboxes []*SandboxInfo
	for _, value := range values {
		if value == nil {
			continue
		}
		data, ok := value.(string)
		if !ok {
			continue
		}

		var sandbox SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

const (
	sessionKeyPrefix = "session:"
	expiryKey        = "session:expiry"
	activityKey      = "session:last_activity"
)

func sessionKey(sessionID string) string {
	return sessionKeyPrefix + sessionID
}

