func TestSelectEntryPoint(t *testing.T) {
	sm := &SessionManager{}

	tests := []struct {
		name         string
		entryPoints  []store.EntryPoint
		requestPath  string
		wantFound    bool
		wantEndpoint string
	}{
		{
			name:        "no entry points",
			entryPoints: []store.EntryPoint{},
			requestPath: "/api/test",
			wantFound:   false,
		},
		{
			name: "prefix match",
			entryPoints: []store.EntryPoint{
				{PathPrefix: "/api", Endpoint: "http://sandbox1:8080"},
			},
			requestPath:  "/api/test",
			wantFound:    true,
			wantEndpoint: "http://sandbox1:8080",
		},
		{
			name: "no prefix match, use first",
			entryPoints: []store.EntryPoint{
				{Endpoint: "http://sandbox1:8080"},
			},
			requestPath:  "/api/test",
			wantFound:    true,
			wantEndpoint: "http://sandbox1:8080",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ep := sm.selectEntryPoint(tt.entryPoints, tt.requestPath)
			if (ep != nil) != tt.wantFound {
				t.Errorf("selectEntryPoint() found = %v, want %v", ep != nil, tt.wantFound)
				return
			}
			if ep != nil && ep.Endpoint != tt.wantEndpoint {
				t.Errorf("selectEntryPoint() endpoint = %v, want %v", ep.Endpoint, tt.wantEndpoint)
			}
		})
	}
}

