package store

import (
	"context"
	"fmt"
	"strconv"
	"sync"
	"time"

	"github.com/valkey-org/valkey-go"
)

type ValkeyStore struct {
	client valkey.Client
	once   sync.Once
}

func NewValkeyStore(addrs []string, password string) (*ValkeyStore, error) {
	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress: addrs,
		Password:    password,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to connect to Valkey: %w", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Dedicate(ctx).Ping().Error(); err != nil {
		return nil, fmt.Errorf("failed to ping Valkey: %w", err)
	}

	return &ValkeyStore{client: client}, nil
}

func (v *ValkeyStore) Ping(ctx context.Context) error {
	return v.client.Dedicate(ctx).Ping().Error()
}

func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox ExpiresAt cannot be zero")
	}

	data, err := jsonMarshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	key := sessionKey(sandbox.SessionID)
	pipe := v.client.Dedicate(ctx)

	if err := pipe.Set(key, data, 0).Error(); err != nil {
		return err
	}
	if err := pipe.ZAdd(expiryKey, []valkey.Z{
		{Score: float64(sandbox.ExpiresAt.Unix()), Member: sandbox.SessionID},
	}).Error(); err != nil {
		return err
	}
	if err := pipe.ZAdd(activityKey, []valkey.Z{
		{Score: float64(time.Now().Unix()), Member: sandbox.SessionID},
	}).Error(); err != nil {
		return err
	}

	return nil
}

func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := v.client.Dedicate(ctx).Get(key).ToString()
	if err != nil {
		if isValkeyNil(err) {
			return nil, &ErrNotFound{}
		}
		return nil, fmt.Errorf("failed to get session: %w", err)
	}

	var sandbox SandboxInfo
	if err := jsonUnmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sessionID string, sandbox *SandboxInfo) error {
	key := sessionKey(sessionID)
	data, err := jsonMarshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	result, err := v.client.Dedicate(ctx).Set(key, data, 0).Condition(valkey.SetMustExist).Error()
	if err != nil {
		return fmt.Errorf("failed to update session: %w", err)
	}
	if result != valkey.ResultSuccess {
		return fmt.Errorf("key not exists")
	}

	return nil
}

func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)
	pipe := v.client.Dedicate(ctx)

	if err := pipe.Del(key).Error(); err != nil {
		return err
	}
	if err := pipe.ZRem(expiryKey, sessionID).Error(); err != nil {
		return err
	}
	if err := pipe.ZRem(activityKey, sessionID).Error(); err != nil {
		return err
	}

	return nil
}

func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*SandboxInfo, error) {
	sessionIDs, err := v.client.Dedicate(ctx).ZRangeByScore(expiryKey, valkey.ZRange{
		Start: "-inf",
		Stop:  strconv.FormatInt(before.Unix(), 10),
		Count: &limit,
	}).ToStrings()
	if err != nil {
		return nil, fmt.Errorf("failed to list expired sessions: %w", err)
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*SandboxInfo, error) {
	sessionIDs, err := v.client.Dedicate(ctx).ZRangeByScore(activityKey, valkey.ZRange{
		Start: "-inf",
		Stop:  strconv.FormatInt(before.Unix(), 10),
		Count: &limit,
	}).ToStrings()
	if err != nil {
		return nil, fmt.Errorf("failed to list inactive sessions: %w", err)
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session ID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	exists, err := v.client.Dedicate(ctx).Exists(key).Result()
	if err != nil {
		return fmt.Errorf("failed to check session existence: %w", err)
	}
	if exists == 0 {
		return &ErrNotFound{}
	}

	return v.client.Dedicate(ctx).ZAdd(activityKey, []valkey.Z{
		{Score: float64(at.Unix()), Member: sessionID},
	}).Error()
}

func (v *ValkeyStore) Close() error {
	return v.client.Close()
}

func (v *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	values, err := v.client.Dedicate(ctx).MGet(keys...).ToStrings()
	if err != nil {
		return nil, fmt.Errorf("failed to load sessions: %w", err)
	}

	var sandboxes []*SandboxInfo
	for _, value := range values {
		if value == "" {
			continue
		}

		var sandbox SandboxInfo
		if err := jsonUnmarshal([]byte(value), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

