}

func NewJWTManager() (*JWTManager, error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key: %w", err)
	}

	return &JWTManager{
		privateKey: privateKey,
	}, nil
}

func (j *JWTManager) GenerateToken(sandbox *store.SandboxInfo) (string, error) {
	claims := jwt.MapClaims{
		"sub":       sandbox.SessionID,
		"sandboxId": sandbox.SandboxID,
		"kind":      sandbox.Kind,
		"namespace": sandbox.Namespace,
		"name":      sandbox.SandboxName,
		"exp":       sandbox.ExpiresAt.Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKeyPEM() string {
	publicKeyBytes, _ := x509.MarshalPKIXPublicKey(&j.privateKey.PublicKey)
	block := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	}
	return string(pem.EncodeToMemory(block))
}

