)

const (
	DefaultMaxConcurrentRequests = 1000
	SessionHeader                = "x-agentcube-session-id"
)

type Config struct {
	Port                  string
	WorkloadManagerURL    string
	EnableTLS             bool
	TLSCertPath           string
	TLSKeyPath            string
	MaxConcurrentRequests int
	Debug                 bool
}

type Server struct {
	config         *Config
	sessionManager *SessionManager
	router         *gin.Engine
}

func NewServer(config *Config, sessionManager *SessionManager) (*Server, error) {
	if config.WorkloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = DefaultMaxConcurrentRequests
	}

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	router.GET("/health/live", handleLiveHealth)
	router.GET("/health/ready", func(c *gin.Context) {
		if sessionManager == nil {
			c.JSON(http.StatusServiceUnavailable, gin.H{
				"status": "not ready",
				"error":  "session manager not available",
			})
			return
		}
		c.JSON(http.StatusOK, gin.H{
			"status": "ready",
		})
	})

	v1Group := router.Group("/v1")
	v1Group.Use(semaphoreMiddleware(config.MaxConcurrentRequests))
	{
		v1Group.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", sessionManager.handleInvoke("AgentRuntime"))
		v1Group.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", sessionManager.handleInvoke("AgentRuntime"))
		v1Group.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", sessionManager.handleInvoke("CodeInterpreter"))
		v1Group.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", sessionManager.handleInvoke("CodeInterpreter"))
	}

return &Server{
		config:         config,
		sessionManager: sessionManager,
		router:         router,
	}, nil
}

	return &Server{
		config:         config,
		sessionManager: sessionManager,
		router:         router,
		transport:      transport,
	}, nil
}

func handleLiveHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status": "alive",
	})
}

func semaphoreMiddleware(maxConcurrent int) gin.HandlerFunc {
	semaphore := make(chan struct{}, maxConcurrent)
	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() { <-semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

type SessionManager struct {
	workloadManagerURL string
	store              store.Store
	jwtManager         *JWTManager
}

func NewSessionManager(workloadManagerURL string, store store.Store, jwtManager *JWTManager) *SessionManager {
	return &SessionManager{
		workloadManagerURL: workloadManagerURL,
		store:              store,
		jwtManager:         jwtManager,
	}
}

func (sm *SessionManager) handleInvoke(kindParam string) gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.GetHeader(SessionHeader)

		var sandboxInfo *store.SandboxInfo
		var err error

		if sessionID != "" {
			sandboxInfo, err = sm.store.GetSandboxBySessionID(c.Request.Context(), sessionID)
			if err != nil {
				if store.IsNotFound(err) {
					c.JSON(http.StatusNotFound, gin.H{
						"error": fmt.Sprintf("Session not found: %s", sessionID),
					})
				} else {
					c.JSON(http.StatusInternalServerError, gin.H{
						"error": "Failed to retrieve session",
					})
				}
				return
			}
		} else {
			sandboxInfo, err = sm.createSession(c.Request.Context(), kindParam, c.Param("namespace"), c.Param("name"))
			if err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{
					"error": fmt.Sprintf("Failed to create session: %v", err),
				})
				return
			}
			sessionID = sandboxInfo.SessionID
		}

		if err := sm.store.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now()); err != nil {
			gin.DefaultWriter.WriteString(fmt.Sprintf("Warning: failed to update activity: %v\n", err))
		}

		if err := sm.forwardToSandbox(c, sandboxInfo); err != nil {
			handleProxyError(c, err)
			return
		}

		if err := sm.store.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now()); err != nil {
			gin.DefaultWriter.WriteString(fmt.Sprintf("Warning: failed to update activity: %v\n", err))
		}

		c.Header(SessionHeader, sessionID)
	}
}

func (sm *SessionManager) createSession(ctx context.Context, kind, namespace, name string) (*store.SandboxInfo, error) {
	return nil, nil
}

func (sm *SessionManager) forwardToSandbox(c *gin.Context, sandbox *store.SandboxInfo) error {
	if len(sandbox.EntryPoints) == 0 {
		return fmt.Errorf("no entry point found for sandbox")
	}

	requestPath := c.Param("path")
	if requestPath == "" {
		requestPath = "/"
	}

	entryPoint := sm.selectEntryPoint(sandbox.EntryPoints, requestPath)
	if entryPoint == nil {
		return fmt.Errorf("no matching entry point")
	}

	targetURL, err := url.Parse(entryPoint.Endpoint)
	if err != nil {
		return fmt.Errorf("invalid endpoint URL: %w", err)
	}

	if entryPoint.Protocol != "" && targetURL.Scheme == "" {
		targetURL.Scheme = strings.ToLower(entryPoint.Protocol)
	}

	director := func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.URL.Path = path.Join(targetURL.Path, requestPath)

		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-Host", req.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		req.Header.Set("X-Forwarded-For", c.ClientIP())

		if kindParam == "Sandbox" || kindParam == "SandboxClaim" {
			token, err := sm.jwtManager.GenerateToken(sandbox)
			if err != nil {
				gin.DefaultWriter.WriteString(fmt.Sprintf("Warning: failed to generate JWT: %v\n", err))
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy := &httputil.ReverseProxy{
		Director: director,
	}

	errorHandler := func(w http.ResponseWriter, r *http.Request, err error) {
		handleProxyError(c, err)
	}

	proxy.ErrorHandler = errorHandler
	proxy.ServeHTTP(c.Writer, c.Request)

	return nil
}

func (sm *SessionManager) selectEntryPoint(entryPoints []store.EntryPoint, requestPath string) *store.EntryPoint {
	for _, ep := range entryPoints {
		if ep.PathPrefix != "" && strings.HasPrefix(requestPath, ep.PathPrefix) {
			return &ep
		}
	}
	if len(entryPoints) > 0 {
		return &entryPoints[0]
	}
	return nil
}

func handleProxyError(c *gin.Context, err error) {
	errStr := err.Error()
	if strings.Contains(errStr, "connection refused") {
		c.JSON(http.StatusBadGateway, gin.H{
			"error": "sandbox unreachable",
		})
	} else if strings.Contains(errStr, "timeout") {
		c.JSON(http.StatusGatewayTimeout, gin.H{
			"error": "sandbox timeout",
		})
	} else {
		c.JSON(http.StatusBadGateway, gin.H{
			"error": "sandbox unreachable",
		})
	}
}

