"""AgentCube Python SDK clients."""

import os
import requests
from typing import Optional, Dict, Any, List, Tuple
from .exceptions import (
    AgentCubeError,
    CommandExecutionError,
    NotFoundError,
    RateLimitError,
)


class ControlPlaneClient:
    """Client for Workload Manager (control plane) operations."""

    def __init__(
        self,
        workload_manager_url: Optional[str] = None,
        auth_token: Optional[str] = None,
        timeout: float = 120.0,
        connect_timeout: float = 5.0,
    ):
        self.base_url = workload_manager_url or os.getenv("WORKLOAD_MANAGER_URL")
        if not self.base_url:
            raise ValueError("Router URL must be provided via argument or ROUTER_URL environment variable")

        self.timeout = timeout
        self.connect_timeout = connect_timeout

        self.session = requests.Session()
        adapter = requests.adapters.HTTPAdapter(pool_connections=10, pool_maxsize=10)
        self.session.mount("http://", adapter)
        self.session.mount("https://", adapter)

        if auth_token:
            self.session.headers.update({"Authorization": f"Bearer {auth_token}"})
        else:
            token_path = "/var/run/secrets/kubernetes.io/serviceaccount/token"
            if os.path.exists(token_path):
                with open(token_path, "r") as f:
                    token = f.read().strip()
                    self.session.headers.update({"Authorization": f"Bearer {token}"})

    def create_session(
        self,
        name: str,
        namespace: str,
        kind: str = "CodeInterpreter",
        metadata: Optional[Dict[str, Any]] = None,
        ttl: int = 3600,
    ) -> str:
        """Create a new sandbox session."""
        url = f"{self.base_url}/v1/{kind.lower()}"
        payload = {
            "kind": kind,
            "name": name,
            "namespace": namespace,
        }
        if metadata:
            payload["metadata"] = metadata

        response = self.session.post(url, json=payload, timeout=self.timeout)
        self._handle_error(response)

        data = response.json()
        session_id = data.get("sessionId")
        if not session_id:
            raise ValueError("No sessionId in response")

        return session_id

    def delete_session(self, session_id: str) -> bool:
        """Delete a sandbox session."""
        url = f"{self.base_url}/v1/code-interpreter/sessions/{session_id}"
        response = self.session.delete(url, timeout=self.timeout)

        if response.status_code == 404:
            return True
        elif response.status_code >= 400:
            return False

        return True

    def _handle_error(self, response: requests.Response):
        """Handle HTTP errors with appropriate exceptions."""
        if response.status_code == 404:
            raise NotFoundError(f"Resource not found: {response.url}")
        elif response.status_code == 429:
            raise RateLimitError(f"Rate limit exceeded: {response.text}")
        elif response.status_code >= 400:
            raise AgentCubeError(f"Request failed: {response.status_code} {response.text}")


class CodeInterpreterDataPlaneClient:
    """Client for Code Interpreter data plane operations."""

    def __init__(
        self,
        base_url: str,
        session_id: str,
        timeout: float = 120.0,
    ):
        self.base_url = base_url.rstrip("/")
        self.session_id = session_id
        self.timeout = timeout
        self.session_header = "x-agentcube-session-id"

        self.session = requests.Session()

    def execute_command(
        self,
        command: List[str],
        timeout: Optional[float] = None,
        working_dir: Optional[str] = None,
        env: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        """Execute a command in the sandbox."""
        url = f"{self.base_url}/api/execute"

        payload = {"command": command}
        if timeout:
            payload["timeout"] = f"{timeout}s"
        if working_dir:
            payload["working_dir"] = working_dir
        if env:
            payload["env"] = env

        effective_timeout = timeout + 2.0 if timeout else self.timeout + 2.0

        headers = {self.session_header: self.session_id}
        response = self.session.post(url, json=payload, headers=headers, timeout=effective_timeout)
        self._handle_error(response)

        data = response.json()
        if data.get("exit_code", 0) != 0:
            raise CommandExecutionError(
                exit_code=data.get("exit_code", -1),
                stderr=data.get("stderr", ""),
                command=command,
            )

        return data

    def write_file(
        self,
        path: str,
        content: str,
        mode: str = "0644",
    ) -> Dict[str, Any]:
        """Write a file using base64 encoding."""
        import base64

        url = f"{self.base_url}/api/files"
        payload = {
            "path": path,
            "content": base64.b64encode(content.encode()).decode(),
            "mode": mode,
        }

        headers = {self.session_header: self.session_id}
        response = self.session.post(url, json=payload, headers=headers, timeout=self.timeout)
        self._handle_error(response)

        return response.json()

    def upload_file(
        self,
        path: str,
        file_content: bytes,
        mode: str = "0644",
    ) -> Dict[str, Any]:
        """Upload a file using multipart form data."""
        url = f"{self.base_url}/api/files"

        files = {"file": (os.path.basename(path), file_content)}
        data = {"path": path, "mode": mode}

        headers = {self.session_header: self.session_id}
        response = self.session.post(url, files=files, data=data, headers=headers, timeout=self.timeout)
        self._handle_error(response)

        return response.json()

    def download_file(self, path: str) -> bytes:
        """Download a file."""
        url = f"{self.base_url}/api/files/{path}"
        headers = {self.session_header: self.session_id}
        response = self.session.get(url, headers=headers, timeout=self.timeout)
        self._handle_error(response)

        return response.content

    def list_files(self, path: str = ".") -> List[Dict[str, Any]]:
        """List files in a directory."""
        url = f"{self.base_url}/api/files"
        params = {"path": path}
        headers = {self.session_header: self.session_id}

        response = self.session.get(url, params=params, headers=headers, timeout=self.timeout)
        self._handle_error(response)

        return response.json().get("files", [])

    def _handle_error(self, response: requests.Response):
        """Handle HTTP errors with appropriate exceptions."""
        if response.status_code == 404:
            raise NotFoundError(f"Resource not found: {response.url}")
        elif response.status_code == 429:
            raise RateLimitError(f"Rate limit exceeded: {response.text}")
        elif response.status_code >= 400:
            raise AgentCubeError(f"Request failed: {response.status_code} {response.text}")


class CodeInterpreterClient:
    """High-level client for Code Interpreter operations."""

    def __init__(
        self,
        name: str,
        namespace: str = "default",
        router_url: Optional[str] = None,
        workload_manager_url: Optional[str] = None,
        session_id: Optional[str] = None,
        timeout: float = 120.0,
    ):
        self.name = name
        self.namespace = namespace

        self.control_plane = ControlPlaneClient(
            workload_manager_url=workload_manager_url,
            timeout=timeout,
        )

        self.session_id = session_id
        self.timeout = timeout
        self._data_plane: Optional[CodeInterpreterDataPlaneClient] = None

        if session_id:
            self._init_data_plane(session_id)

        self.router_url = router_url or os.getenv("ROUTER_URL")
        if not self.router_url and not session_id:
            raise ValueError("Router URL must be provided via argument or ROUTER_URL environment variable")

    def _init_data_plane(self, session_id: str):
        """Initialize data plane client."""
        if not self.router_url:
            raise ValueError("Router URL is required to initialize data plane")

        base_url = f"{self.router_url.rstrip('/')}/v1/namespaces/{self.namespace}/code-interpreters/{self.name}/invocations"
        self._data_plane = CodeInterpreterDataPlaneClient(base_url, session_id, self.timeout)

    def create_session(self, ttl: int = 3600) -> str:
        """Create a new session."""
        self.session_id = self.control_plane.create_session(self.name, self.namespace, "CodeInterpreter", ttl=ttl)
        self._init_data_plane(self.session_id)
        return self.session_id

    def execute_command(
        self,
        command: List[str],
        timeout: Optional[float] = None,
        working_dir: Optional[str] = None,
        env: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        """Execute a command."""
        if not self._data_plane:
            if self.session_id:
                self._init_data_plane(self.session_id)
            else:
                self.create_session()

        return self._data_plane.execute_command(command, timeout, working_dir, env)

    def run_code(
        self,
        code: str,
        language: str = "python",
        timeout: Optional[float] = None,
    ) -> Dict[str, Any]:
        """Run code in the specified language."""
        if language.lower() in ("python", "py", "python3"):
            import time
            timestamp = int(time.time() * 1000)
            filename = f"code_{timestamp}.py"
            self.write_file(filename, code)
            command = ["python3", filename]
            return self.execute_command(command, timeout)
        else:
            raise ValueError(f"Unsupported language: {language}")

    def write_file(
        self,
        path: str,
        content: str,
        mode: str = "0644",
    ) -> Dict[str, Any]:
        """Write a file."""
        if not self._data_plane:
            if self.session_id:
                self._init_data_plane(self.session_id)
            else:
                self.create_session()

        return self._data_plane.write_file(path, content, mode)

    def upload_file(
        self,
        path: str,
        file_content: bytes,
        mode: str = "0644",
    ) -> Dict[str, Any]:
        """Upload a file."""
        if not self._data_plane:
            if self.session_id:
                self._init_data_plane(self.session_id)
            else:
                self.create_session()

        return self._data_plane.upload_file(path, file_content, mode)

    def download_file(self, path: str) -> bytes:
        """Download a file."""
        if not self._data_plane:
            if self.session_id:
                self._init_data_plane(self.session_id)
            else:
                self.create_session()

        return self._data_plane.download_file(path)

    def list_files(self, path: str = ".") -> List[Dict[str, Any]]:
        """List files in a directory."""
        if not self._data_plane:
            if self.session_id:
                self._init_data_plane(self.session_id)
            else:
                self.create_session()

        return self._data_plane.list_files(path)

    def stop(self):
        """Stop and cleanup the session."""
        if self._data_plane:
            self._data_plane = None

        if self.session_id:
            try:
                self.control_plane.delete_session(self.session_id)
            except Exception:
                pass
            self.session_id = None

    def __enter__(self):
        """Context manager entry."""
        if not self.session_id:
            self.create_session()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.stop()
        return False


class AgentRuntimeClient:
    """Client for Agent Runtime operations."""

    def __init__(
        self,
        name: str,
        namespace: str = "default",
        router_url: Optional[str] = None,
        timeout: float = 120.0,
        connect_timeout: float = 5.0,
    ):
        self.name = name
        self.namespace = namespace
        self.router_url = router_url or os.getenv("ROUTER_URL")
        if not self.router_url:
            raise ValueError("Router URL must be provided via argument or ROUTER_URL environment variable")

        self.timeout = timeout
        self.connect_timeout = connect_timeout
        self.session_id: Optional[str] = None
        self.SESSION_HEADER = "x-agentcube-session-id"

        self.session = requests.Session()

    def _bootstrap_session(self):
        """Bootstrap session by calling the invocation endpoint."""
        url = f"{self.router_url.rstrip('/')}/v1/namespaces/{self.namespace}/agent-runtimes/{self.name}/invocations/"
        response = self.session.get(url, timeout=(self.connect_timeout, self.timeout))

        self.session_id = response.headers.get(self.SESSION_HEADER)
        if not self.session_id:
            raise ValueError(f"Missing required response header: {self.SESSION_HEADER}")

    def invoke(
        self,
        payload: Dict[str, Any],
        timeout: Optional[float] = None,
    ) -> Dict[str, Any]:
        """Invoke the agent runtime."""
        if not self.session_id:
            self._bootstrap_session()

        url = f"{self.router_url.rstrip('/')}/v1/namespaces/{self.namespace}/agent-runtimes/{self.name}/invocations/"
        headers = {self.SESSION_HEADER: self.session_id}

        effective_timeout = timeout if timeout is not None else self.timeout
        timeout_tuple = (self.connect_timeout, effective_timeout)

        response = self.session.post(url, json=payload, headers=headers, timeout=timeout_tuple)
        self._handle_error(response)

        return response.json()

    def _handle_error(self, response: requests.Response):
        """Handle HTTP errors with appropriate exceptions."""
        if response.status_code == 404:
            raise NotFoundError(f"Resource not found: {response.url}")
        elif response.status_code == 429:
            raise RateLimitError(f"Rate limit exceeded: {response.text}")
        elif response.status_code >= 400:
