"""Unit tests for AgentCube session store."""

import pytest
import time
from unittest.mock import Mock, patch
from agentcube_sdk.store import (
    RedisStore,
    Store,
    SandboxInfo,
    EntryPoint,
    ErrNotFound,
)


class MockRedis:
    def __init__(self):
        self.data = {}
        self.sorted_sets = {}

    def ping(self):
        return True

    def set(self, key, value):
        self.data[key] = value

    def get(self, key):
        return self.data.get(key)

    def delete(self, key):
        if key in self.data:
            del self.data[key]

    def zadd(self, key, score, member):
        if key not in self.sorted_sets:
            self.sorted_sets[key] = {}
        self.sorted_sets[key][member] = score

    def zrem(self, key, member):
        if key in self.sorted_sets and member in self.sorted_sets[key]:
            del self.sorted_sets[key][member]

    def zrangebyscore(self, key, min_score, max_score, limit=None):
        if key not in self.sorted_sets:
            return []
        result = [
            m for m, s in self.sorted_sets[key].items()
            if min_score <= s <= max_score
        ]
        if limit:
            result = result[:limit]
        return result


class TestSandboxInfo:
    def test_create_sandbox_info(self):
        info = SandboxInfo(
            session_id="test-session",
            sandbox_id="test-sandbox",
            sandbox_name="test-name",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[
                EntryPoint(
                    path_prefix="/api",
                    protocol="http",
                    endpoint="127.0.0.1:8080",
                )
            ],
            expires_at=time.time() + 3600,
        )

        assert info.session_id == "test-session"
        assert info.kind == "CodeInterpreter"
        assert len(info.entry_points) == 1


class TestRedisStore:
    def test_ping(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        result = store.ping()
        assert result is True

    def test_store_and_get_sandbox(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        sandbox = SandboxInfo(
            session_id="test-session",
            sandbox_id="test-sandbox",
            sandbox_name="test-name",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[],
            expires_at=time.time() + 3600,
        )

        store.store_sandbox(sandbox)
        retrieved = store.get_sandbox_by_session_id("test-session")

        assert retrieved is not None
        assert retrieved.session_id == "test-session"

    def test_get_nonexistent_sandbox_raises_error(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        with pytest.raises(ErrNotFound):
            store.get_sandbox_by_session_id("nonexistent")

    def test_delete_sandbox(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        sandbox = SandboxInfo(
            session_id="test-session",
            sandbox_id="test-sandbox",
            sandbox_name="test-name",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[],
            expires_at=time.time() + 3600,
        )

        store.store_sandbox(sandbox)
        store.delete_sandbox_by_session_id("test-session")

        with pytest.raises(ErrNotFound):
            store.get_sandbox_by_session_id("test-session")

    def test_list_expired_sandboxes(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        now = time.time()

        sandbox1 = SandboxInfo(
            session_id="expired1",
            sandbox_id="sandbox1",
            sandbox_name="name1",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[],
            expires_at=now - 100,
        )

        sandbox2 = SandboxInfo(
            session_id="expired2",
            sandbox_id="sandbox2",
            sandbox_name="name2",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[],
            expires_at=now - 200,
        )

        store.store_sandbox(sandbox1)
        store.store_sandbox(sandbox2)

        expired = store.list_expired_sandboxes(now, 10)
        assert len(expired) == 2

    def test_list_inactive_sandboxes(self):
        mock_redis = MockRedis()
        store = RedisStore(mock_redis)

        sandbox = SandboxInfo(
            session_id="test-session",
            sandbox_id="test-sandbox",
            sandbox_name="test-name",
            kind="CodeInterpreter",
            namespace="default",
            entry_points=[],
            expires_at=time.time() + 3600,
        )

        store.store_sandbox(sandbox)
        store.update_session_last_activity("test-session", time.time() - 1000)

        inactive = store.list_inactive_sandboxes(time.time() - 900, 10)
        assert len(inactive) == 1


if __name__ == "__main__":
    pytest.main([__file__, "-v"])
